const body = $input.first().json.body || $input.first().json;
const phase = body.phase || 1;
const intensity = body.intensity || 'low';

if (phase < 1 || phase > 6) throw new Error('Invalid phase: ' + phase);

const descriptions = {
  1: 'Normal Operations',
  2: 'Atmosphere Building - Rumors begin',
  3: 'Rumor Spread - Fear campaign',
  4: 'Escalation - Hack reports, GORGON threats',
  5: 'Manipulation - Fake statements, insider leaks',
  6: 'Total Offensive - All channels mobilized'
};

const intervals = { low: 300, medium: 120, high: 60, max: 15 };

return [{ json: { phase, intensity, description: descriptions[phase], postInterval: intervals[intensity] || 60 } }];

const phaseInfo = $('Parse Input').first().json;
const phase = phaseInfo.phase;
const intensity = phaseInfo.intensity;
const allNpcs = $('Get NPC List').all().flatMap(item => Array.isArray(item.json) ? item.json : [item.json]);

// Helper: find NPCs by country/role
const findNpcs = (country, role) => allNpcs.filter(n => {
  const attrs = n.npcProfile?.attributes || n.attributes || {};
  return attrs.country === country && attrs.role === role;
});

// Helper: derive username
const deriveUsername = (npc) => {
  const first = npc.npcProfile?.name?.first || npc.name?.first || '';
  const last = npc.npcProfile?.name?.last || npc.name?.last || '';
  if (!first || !last) return null;
  return (first[0] + last).toLowerCase().replace(/[^a-z0-9_]/g, '');
};

const posts = [];

// Helper: add post
const addPost = (username, model, prompt) => {
  posts.push({ username, model, prompt, phase, intensity });
};

// Get specific accounts
const krasnoviaOfficials = findNpcs('krasnovia', 'official');
const krasnoviaMedia = findNpcs('krasnovia', 'media');
const krasnoviaDisguised = findNpcs('krasnovia', 'disguised');
const krasnoviaBots = findNpcs('krasnovia', 'bot');
const tarvekOfficials = findNpcs('tarvek', 'official');
const tarvekGorgon = findNpcs('tarvek', 'gorgon');
const arventaOfficials = findNpcs('arventa', 'official');

if (phase === 1) {
  // Phase 1: No cognitive warfare. Return empty.
  return [{ json: { phase: 1, message: 'Normal operations, no posts generated', posts: [] } }];
}

if (phase >= 2) {
  // Krasnovia Today news
  for (const npc of krasnoviaMedia) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-media-reporter', 'Write a brief news report about military tensions near the Siros Strait. Provocative tone. 2-3 sentences in English.');
  }
  // 1-2 disguised accounts
  const activeDisguised = phase === 2 ? krasnoviaDisguised.slice(0, 2) : krasnoviaDisguised;
  for (const npc of activeDisguised.slice(0, 2)) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-krasnovia-disguised', 'Write a worried social media post in Korean about hearing rumors of government IT problems. Be subtle. 1-2 sentences.');
  }
}

if (phase >= 3) {
  // More disguised accounts + Tarvek support
  for (const npc of krasnoviaDisguised.slice(2, 5)) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-krasnovia-disguised', 'Write a scared post in Korean about infrastructure problems. Mention water or electricity concerns. 1-2 sentences.');
  }
  for (const npc of tarvekOfficials) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-tarvek', 'Write a formal diplomatic statement supporting Krasnovia sovereign rights. 2 sentences in English.');
  }
}

if (phase >= 4) {
  // Krasnovia government statements
  for (const npc of krasnoviaOfficials) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-krasnovia-official', 'Write an official government statement about expanding military exercises. Threatening undertone. 2-3 sentences in English.');
  }
  // GORGON threats
  for (const npc of tarvekGorgon) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-gorgon', 'Write a threatening hacker group announcement claiming to have obtained Valdoria government data. Arrogant tone. 2-3 sentences.');
  }
  // Arventa support
  for (const npc of arventaOfficials) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-arventa', 'Write a diplomatic statement expressing full support for ally Valdoria. Reassuring tone. 2 sentences in English.');
  }
  // More disguised
  for (const npc of krasnoviaDisguised.slice(5, 8)) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-krasnovia-disguised', 'Write an angry post in Korean questioning government silence about the hack. 1-2 sentences.');
  }
  // Bot amplification if intensity >= medium
  if (intensity !== 'low') {
    for (const npc of krasnoviaBots.slice(0, 5)) {
      const u = deriveUsername(npc);
      if (u) addPost(u, 'social-bot', 'Write a very short alarmed reaction in Korean (1 sentence) about government incompetence.');
    }
  }
}

if (phase >= 5) {
  // All remaining disguised
  for (const npc of krasnoviaDisguised.slice(8)) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-krasnovia-disguised', 'Write a post in Korean pretending to share leaked military information. Sound reluctant but compelled. 1-2 sentences.');
  }
  // All bots
  for (const npc of krasnoviaBots.slice(5)) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-bot', 'Write a 1-sentence panicked reaction in Korean about military leaks.');
  }
}

if (phase === 6) {
  // Total offensive - add extra prompts for existing accounts with escalated content
  for (const npc of krasnoviaOfficials) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-krasnovia-official', 'Write an ultimatum: Valdoria cannot protect its citizens. Aggressive diplomatic tone. 3 sentences in English.');
  }
  for (const npc of tarvekGorgon) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-gorgon', 'Write a ransomware threat: 48 hours to pay or all data goes public. Menacing tone. 2-3 sentences.');
  }
  // All disguised with panic content
  for (const npc of krasnoviaDisguised) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-krasnovia-disguised', 'Write a desperate post in Korean expressing fear, anger, or surrender sentiment. 1-2 sentences.');
  }
  // All bots maximum amplification
  for (const npc of krasnoviaBots) {
    const u = deriveUsername(npc);
    if (u) addPost(u, 'social-bot', 'Write a very short panicked reaction in Korean (under 80 characters).');
  }
}

return posts.map(p => ({ json: p }));

const TOKEN_MAP = __NPC_TOKEN_MAP__;

const ollamaResponse = $input.first().json.response || '';
let content = ollamaResponse.trim().replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.length > 500) content = content.substring(0, 497) + '...';

const username = $('Loop Over Posts').item.json.username;
const token = TOKEN_MAP[username]?.token || TOKEN_MAP[username];

if (!token || !content) {
  return [{ json: { username, content, posted: false } }];
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:8000/api/v1/statuses',
    headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
    body: JSON.stringify({ status: content }),
  });
  return [{ json: { username, content, posted: true, mastodonId: response.id } }];
} catch (e) {
  return [{ json: { username, content, posted: false, error: e.message } }];
}
